  ('locality-6f0ba476-moex-00180', 'locality-6f0ba476', 'locality-6f0ba476-moex-113-f6c431ec', 'sub-locality-6f0ba476-04', NULL, 'single_choice', '布坎南（J.Buchanan）與杜洛克（G.Tullock）所提出的最適憲政模型係指：', '["最適投票決議百分比決定於外部成本與決策成本皆為最小", "最適投票決議百分比決定於外部成本與決策成本之加總為最小", "最適投票議案數決定於社會福利最大", "最適投票議案數決定於社會邊際成本最小"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:02+00:00", "source_pdf_sha1": "b270d478169a", "answer_pdf_sha1": "465f5642fec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "312", "s": "1209", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
